import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, icon } from 'decantr/components';

code.example:
function QuickActions({ actions }) {
  const { div, span } = tags;

  return div({ class: css('_grid _gc2 _sm:gc3 _lg:gc4 _gap3') },
    ...actions.map(action =>
      Card({ hover: true, class: css('_cursor[pointer]'), onclick: action.handler },
        Card.Body({ class: css('_flex _col _aic _gap2 _p4 _tc') },
          div({ class: css('_w10 _h10 _flex _center _r3 _bgprimary/10') },
            icon(action.icon, { size: '1.25rem', class: css('_fgprimary') })
          ),
          span({ class: css('_textsm _medium') }, action.label)
        )
      )
    )
  );
}
